read_verilog -sv <<EOF

module top(q, d, clk, rst);
	input wire clk;
	input wire rst;
	input wire [1:0] d;
	output reg [1:0] q;
	always @(posedge clk, posedge rst) begin
		if (rst) begin
			q <= 0;
		end else begin
			q <= d;
			$display("q <= %x", d);
			assert(!(d & (d - 1)));
		end
	end
endmodule

EOF
